-- =============================================
-- OI Database Project - FACT_EXPERIMENT_RECOMMENDATIONS Table
-- =============================================
--
-- Purpose: Weekly recommendations generated by the experiment learning engine
-- Method: INSERT (SP_EXPERIMENT_WEEKLY_REVIEW appends weekly)
-- Project: onyga-482313
-- Dataset: OI
--
-- =============================================

CREATE TABLE IF NOT EXISTS `onyga-482313.OI.FACT_EXPERIMENT_RECOMMENDATIONS` (
  -- Keys
  recommendation_id STRING NOT NULL,
  week_start_date DATE NOT NULL,  -- Monday of the recommendation week
  generated_at TIMESTAMP NOT NULL,

  -- Classification
  category STRING NOT NULL,
  -- EXPERIMENT_CONTINUE: keep running, showing positive results
  -- EXPERIMENT_STOP: no lift, recommend stopping
  -- EXPERIMENT_REVIEW: mixed signals, needs attention
  -- NEW_EXPERIMENT: suggest starting a new experiment
  -- SEASONAL_ACTION: upcoming holiday requires action
  -- OPTIMIZATION: bid/budget adjustment for active experiment
  -- COVERAGE_GAP: high-impression term with no ads coverage

  priority STRING NOT NULL,  -- HIGH, MEDIUM, LOW

  -- Content
  title STRING NOT NULL,
  detail STRING,

  -- Context (nullable, depends on category)
  experiment_id STRING,
  asin STRING,
  search_term STRING,
  campaign_name STRING,

  -- Supporting metrics
  metric_value FLOAT64,  -- primary metric (e.g., organic lift %, ROAS, impressions)
  metric_label STRING,   -- what the metric represents

  PRIMARY KEY (recommendation_id) NOT ENFORCED
)
PARTITION BY DATE_TRUNC(week_start_date, MONTH)
CLUSTER BY category, priority
OPTIONS (
  description = "Weekly recommendations from the experiment learning engine. Categories: EXPERIMENT_CONTINUE/STOP/REVIEW, NEW_EXPERIMENT, SEASONAL_ACTION, OPTIMIZATION, COVERAGE_GAP."
);
